<script setup lang="ts">import{computed}from'vue';import{useI18n}from'vue-i18n';import type{SubtitleConfig}from'@/types/subtitles';const model=defineModel<SubtitleConfig>({required:true});const{t}=useI18n();const fields=computed({get:()=>model.value.dialogueFields.join(', '),set:(v:string)=>model.value.dialogueFields=v.split(',').map(x=>x.trim()).filter(Boolean)})</script>
<template><section class="form-section"><h2>{{t('subtitles.behavior.title')}}</h2><div class="form-grid"><label class="check"><input v-model="model.enabled" type="checkbox">{{t('subtitles.behavior.enabled')}}</label><label>{{t('subtitles.behavior.close')}}<input v-model.number="model.closeSeconds" type="number" min="1" max="3600"></label><label>{{t('subtitles.behavior.mode')}}<select v-model="model.contentMode"><option value="dialogue">{{t('subtitles.behavior.dialogue')}}</option><option value="all">{{t('subtitles.behavior.all')}}</option></select></label><label class="wide">{{t('subtitles.behavior.fields')}}<input v-model="fields" type="text"></label><label class="check"><input v-model="model.plainTextFallback" type="checkbox">{{t('subtitles.behavior.fallback')}}</label><label class="check"><input v-model="model.showReasoning" type="checkbox">{{t('subtitles.behavior.reasoning')}}</label><label class="check"><input v-model="model.clickThrough" type="checkbox">{{t('subtitles.behavior.clickThrough')}}</label><label class="check"><input v-model="model.forceUpstreamStream" type="checkbox">{{t('subtitles.behavior.forceStream')}}</label></div></section></template>
